Create a new `UnregisterAgentDialog` component at `apps/client/src/layers/features/agents-list/ui/UnregisterAgentDialog.tsx` that replaces the inline confirm/cancel unregister pattern in AgentRow with a proper AlertDialog.

**Props interface:**

```typescript
interface UnregisterAgentDialogProps {
  /** Display name of the agent being unregistered. */
  agentName: string;
  /** Agent ID for the unregister mutation. */
  agentId: string;
  /** Controlled open state. */
  open: boolean;
  /** Callback when the dialog opens or closes. */
  onOpenChange: (open: boolean) => void;
}
```

**Full implementation:**

```tsx
import {
  AlertDialog,
  AlertDialogContent,
  AlertDialogHeader,
  AlertDialogFooter,
  AlertDialogTitle,
  AlertDialogDescription,
  AlertDialogAction,
  AlertDialogCancel,
} from '@/layers/shared/ui/alert-dialog';
import { useUnregisterAgent } from '@/layers/entities/mesh';

export function UnregisterAgentDialog({
  agentName,
  agentId,
  open,
  onOpenChange,
}: UnregisterAgentDialogProps) {
  const { mutate: unregister } = useUnregisterAgent();

  return (
    <AlertDialog open={open} onOpenChange={onOpenChange}>
      <AlertDialogContent>
        <AlertDialogHeader>
          <AlertDialogTitle>Unregister {agentName}?</AlertDialogTitle>
          <AlertDialogDescription>
            This will remove the agent from the mesh registry. The agent can be re-discovered by
            scanning its project directory.
          </AlertDialogDescription>
        </AlertDialogHeader>
        <AlertDialogFooter>
          <AlertDialogCancel>Cancel</AlertDialogCancel>
          <AlertDialogAction
            className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
            onClick={() => unregister(agentId)}
          >
            Unregister
          </AlertDialogAction>
        </AlertDialogFooter>
      </AlertDialogContent>
    </AlertDialog>
  );
}
```

Key design decisions:
- `useUnregisterAgent()` is called inside this component (not passed as a callback) to co-locate mutation lifecycle with the dialog.
- Confirm button uses destructive styling (`bg-destructive text-destructive-foreground hover:bg-destructive/90`).
- Dialog description explains that re-discovery is possible (reduces user anxiety about irreversibility).

**Add to barrel export** in `apps/client/src/layers/features/agents-list/index.ts`:

