**Create test file** at `apps/client/src/layers/features/agents-list/__tests__/FleetHealthBar.test.tsx`:

```typescript
/**
 * @vitest-environment jsdom
 */
import { describe, it, expect, vi, beforeEach } from 'vitest';
import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom/vitest';
import type { MeshStatus } from '@dorkos/shared/mesh-schemas';
import { FleetHealthBar } from '../ui/FleetHealthBar';

const baseMeshStatus: MeshStatus = {
  activeCount: 3,
  inactiveCount: 2,
  staleCount: 1,
  unreachableCount: 0,
  totalAgents: 6,
  lastUpdated: new Date().toISOString(),
};

describe('FleetHealthBar', () => {
  const defaultProps = {
    status: baseMeshStatus,
    activeFilter: 'all' as const,
    onStatusFilter: vi.fn(),
  };

  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('renders colored dots and counts for each non-zero status', () => {
    render(<FleetHealthBar {...defaultProps} />);
    expect(screen.getByText('3')).toBeInTheDocument();
    expect(screen.getByText('2')).toBeInTheDocument();
    expect(screen.getByText('1')).toBeInTheDocument();
    // unreachable is 0 so should not be present
    expect(screen.queryByText('Unreachable')).not.toBeInTheDocument();
  });

  it('does not render segments with zero count', () => {
    render(<FleetHealthBar {...defaultProps} status={{ ...baseMeshStatus, staleCount: 0 }} />);
    expect(screen.queryByText('Stale')).not.toBeInTheDocument();
  });

  it('calls onStatusFilter with correct status when clicked', () => {
    render(<FleetHealthBar {...defaultProps} />);
    fireEvent.click(screen.getByText('3')); // active count
    expect(defaultProps.onStatusFilter).toHaveBeenCalledWith('active');
  });

  it('calls onStatusFilter with all to toggle off active filter', () => {
    render(<FleetHealthBar {...defaultProps} activeFilter="active" />);
    fireEvent.click(screen.getByText('3')); // active count, already active
    expect(defaultProps.onStatusFilter).toHaveBeenCalledWith('all');
  });

  it('renders total agent count', () => {
    render(<FleetHealthBar {...defaultProps} />);
    expect(screen.getByText('6 agents')).toBeInTheDocument();
  });

  it('uses singular agent for count of 1', () => {
    render(<FleetHealthBar {...defaultProps} status={{ ...baseMeshStatus, totalAgents: 1 }} />);
    expect(screen.getByText('1 agent')).toBeInTheDocument();
  });
});
```

**Acceptance criteria:**
- Renders colored dots and counts for each non-zero status.
- Does not render segments with zero count.
- Clicking a count calls `onStatusFilter` with the correct status.
- Clicking an already-active filter toggles it off (calls with `'all'`).
- Renders total agent count with correct plural/singular.
- Status labels hidden on mobile via `hidden sm:inline` class.
- All count values use `tabular-nums`.
- All 6 tests pass.
- Component is exported from the barrel `index.ts`.

Add a CSS `@keyframes` animation for the health dot pulse effect on active agents. This animation is used by the AgentRow component (task 1.4) to indicate active agent status.

**File to modify:** `apps/client/src/index.css`

**Add the following CSS** (append near the bottom of the file, after any existing custom animations):

```css
@keyframes health-pulse {
  0%,
  100% {
    box-shadow: 0 0 0 0 rgb(16 185 129 / 0.4);
  }
  50% {
    box-shadow: 0 0 0 4px rgb(16 185 129 / 0);
  }
}
.animate-health-pulse {
